### Backend (Node.js + Express.js + MongoDB)

First, ensure you have Node.js installed. Then, create a new directory for your project and initialize it:

```bash
mkdir room-management-system
cd room-management-system
npm init -y
```

Install the necessary dependencies:

```bash
npm install express mongoose body-parser cors
```

Create a file named `server.js`:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const bodyParser = require('body-parser');
const cors = require('cors');

const app = express();
app.use(bodyParser.json());
app.use(cors());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/roommanagement', {
    useNewUrlParser: true,
    useUnifiedTopology: true
});

const db = mongoose.connection;
db.on('error', console.error.bind(console, 'connection error:'));
db.once('open', () => {
    console.log("Connected to MongoDB");
});

// Room Schema
const roomSchema = new mongoose.Schema({
    name: String,
    capacity: Number,
    isAvailable: Boolean
});

const Room = mongoose.model('Room', roomSchema);

// API Routes
app.get('/rooms', async (req, res) => {
    const rooms = await Room.find();
    res.send(rooms);
});

app.post('/rooms', async (req, res) => {
    const room = new Room(req.body);
    await room.save();
    res.send(room);
});

app.put('/rooms/:id', async (req, res) => {
    const room = await Room.findByIdAndUpdate(req.params.id, req.body, { new: true });
    res.send(room);
});

app.delete('/rooms/:id', async (req, res) => {
    await Room.findByIdAndDelete(req.params.id);
    res.send({ message: "Room deleted" });
});

const port = process.env.PORT || 5000;
app.listen(port, () => {
    console.log(`Server running on port ${port}`);
});
```

